```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create an adaptor and a binary_stream over the read-only span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket packet{};

    // 1. Read packet_id
    stream(packet.packet_id);

    // 2. Read username using length prefix
    //    We read into a std::string directly; Hexi's default for std::string
    //    is length‑prefixed.
    stream(packet.username);

    // 3. Read the score count, then read the scores vector
    uint32_t score_count{};
    stream(score_count);

    // Ensure the vector has the correct size then read elements
    packet.scores.resize(score_count);
    stream.read_container(packet.scores);

    // 4. Read metadata string as null‑terminated for zero‑copy
    {
        std::string_view metadata_view{};
        stream(hexi::adaptors::null_terminated(metadata_view));
        packet.metadata.assign(metadata_view.begin(), metadata_view.end());
    }

    // 5. Skip any remaining padding bytes (if any)
    {
        const auto remaining = adaptor.size() - adaptor.read_pos();
        if (remaining > 0) {
            stream.skip(remaining);
        }
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    PacketInfo info{};

    // 1. Use span() to get a zero‑copy view of the packet_id (first 4 bytes)
    {
        std::span<const std::byte, sizeof(uint32_t)> id_span{};
        stream(hexi::adaptors::span(id_span));
        // Convert from bytes to uint32_t (assuming native endianness)
        uint32_t value{};
        std::memcpy(&value, id_span.data(), sizeof(uint32_t));
        info.packet_id = value;
    }

    // 2. Read username using prefixed adaptor to get a string_view
    {
        std::string_view username_view{};
        stream(hexi::adaptors::prefixed(username_view));
        info.username = username_view;
    }

    // 3. Skip the scores vector without reading its elements
    //    Layout assumed: uint32_t count; followed by count * sizeof(uint32_t) bytes
    {
        uint32_t score_count{};
        stream(score_count);

        std::size_t bytes_to_skip = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
        if (bytes_to_skip > 0) {
            stream.skip(bytes_to_skip);
        }
    }

    // We intentionally do not touch metadata or padding here.

    return info;
}
