    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a Hexi buffer adaptor over the read-only span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream for reading
    hexi::binary_stream stream(adaptor);

    // Obtain a zero-copy span view over the header bytes
    // The header layout is: uint8_t, uint8_t, uint16_t (4 bytes total)
    auto header_span = stream.span<std::byte>(sizeof(PacketHeader));

    // Interpret the bytes as a PacketHeader without copying
    const auto* hdr = reinterpret_cast<const PacketHeader*>(header_span.data());

    // Return by value (the function's job is to "read" the header;
    // the zero-copy is in how we accessed it from the buffer)
    return *hdr;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Create a Hexi buffer adaptor over the read-only span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream for reading
    hexi::binary_stream stream(adaptor);

    // Use Hexi's view() to obtain a zero-copy, null-terminated string view
    // This will read until it encounters a '\0' delimiter in the buffer
    auto message_view = stream.view<char>();

    // Convert to std::string_view and return
    return std::string_view(message_view.data(), message_view.size());
}
