std::vector<uint32_t> read_item_batch(const std::span<const uint8_t> buffer) {
    // Wrap the input span in a Hexi buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read the item count (uint32_t)
    std::uint32_t item_count{};
    stream >> item_count;

    // Prepare the container and read all items using Hexi's container API
    std::vector<std::uint32_t> items;
    items.reserve(item_count);          // optional, for efficiency
    stream.read_container(items, item_count);

    return items;
}
