```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Clamp to available data
    const std::size_t to_read = std::min(bytes_to_read, source_buffer.size());

    // Wrap the source buffer in a read-only adaptor
    hexi::buffer_adaptor adaptor(std::span<const std::uint8_t>(source_buffer.data(), source_buffer.size()));
    hexi::binary_stream stream(adaptor);

    std::vector<std::uint8_t> result(to_read);
    if (to_read > 0) {
        stream.read(result.data(), to_read);
    }

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Ensure destination is large enough
    if (dest_buffer.size() < source_data.size()) {
        dest_buffer.resize(source_data.size());
    }

    // Wrap the destination buffer in a write-capable adaptor
    hexi::buffer_adaptor adaptor(std::span<std::uint8_t>(dest_buffer.data(), dest_buffer.size()));
    hexi::binary_stream stream(adaptor);

    if (!source_data.empty()) {
        stream.write(source_data.data(), source_data.size());
        // Inform adaptor that we have written this many bytes, if needed
        adaptor.advance_write(source_data.size());
    }
}
