#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a read-only adaptor over the input buffer
    hexi::buffer_adaptor adaptor(std::span<const std::uint8_t>(buffer.data(), buffer.size()));

    // Limit peek size to available data
    const auto available = adaptor.size();
    const auto to_copy = std::min<std::size_t>(bytes_to_peek, available);

    std::vector<std::uint8_t> result(to_copy);
    if (to_copy == 0) {
        return result;
    }

    // Use copy() to peek without advancing the read cursor
    adaptor.copy(result.data(), to_copy);

    // adaptor's read position is unchanged; return the peeked bytes
    return result;
}
