#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Wrap the buffer with a read-only adaptor
    hexi::buffer_adaptor adaptor(
        std::span<const std::uint8_t>(buffer.data(), buffer.size())
    );

    // The current read position is at the adaptor's offset 0
    // for the underlying span, so return the underlying pointer.
    return buffer.empty() ? nullptr : buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Wrap the buffer with a read/write adaptor
    hexi::buffer_adaptor adaptor(
        std::span<std::uint8_t>(buffer.data(), buffer.size())
    );

    // Writes start at the adaptor's current write position, which for a
    // freshly constructed adaptor over a vector is at buffer.data() + adaptor.size().
    // Since adaptor.size() corresponds to the number of readable bytes, the write
    // pointer is at the end of the current data.
    return buffer.empty() ? nullptr : buffer.data() + buffer.size();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // For a std::vector, the "readable" size is size(),
    // and the free space is capacity() - size().
    BufferInfo info{};
    info.readable_size = buffer.size();
    info.free_space    = buffer.capacity() - buffer.size();
    return info;
}

