```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Adapt the read-only span into a Hexi buffer and create a binary_stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview the first byte (data_type) without advancing the read pointer
    std::byte preview_byte{};
    // peek(index, count, dest) reads without advancing
    stream.peek(0, sizeof(uint8_t), &preview_byte);
    result.data_type = static_cast<uint8_t>(preview_byte);

    // Check there is at least enough data for the header: data_type + item_count
    // stream.size() is the total size; we've not advanced the read pointer yet
    const auto total_size = stream.size();
    constexpr std::size_t header_size = sizeof(uint8_t) + sizeof(uint32_t);
    if (total_size < header_size) {
        // Not enough data; just return what we know (data_type) and empty vectors
        return result;
    }

    // Now actually read the header in order, which advances the read pointer
    uint8_t data_type{};
    uint32_t item_count{};
    stream >> data_type >> item_count;

    // Sanity-check that the declared payload fits in the buffer
    std::size_t items_bytes =
        static_cast<std::size_t>(item_count) *
        (data_type == 0 ? sizeof(uint32_t) : sizeof(float));

    if (header_size + items_bytes > total_size) {
        // Inconsistent / truncated buffer; return header info only
        result.data_type = data_type;
        return result;
    }

    result.data_type = data_type;

    if (data_type == 0) {
        // Integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (data_type == 1) {
        // Floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    } else {
        // Unknown type; nothing more to read
    }

    return result;
}
