```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Calculate required size: 4 bytes for header + 4 bytes per item.
    const std::size_t required_bytes = sizeof(header) + items.size() * sizeof(uint32_t);

    // Check if the buffer has enough capacity to hold the data.
    if (buffer.size() < required_bytes) {
        return false;
    }

    // Create an adaptor over the entire buffer.
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw); // avoid exceptions

    // Get the current write pointer and ensure there is enough contiguous space.
    std::size_t available = adaptor.capacity() - adaptor.size();
    if (available < required_bytes) {
        return false;
    }

    // Write header and items using the binary stream.
    stream << header;
    stream.write_container(items);

    // Check if any error occurred during writing.
    if (!stream) {
        return false;
    }

    // Advance the adaptor's write position to reflect written data.
    adaptor.advance_write(required_bytes);

    return true;
}
```

