```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Wrap the incoming span in a Hexi buffer_adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream over the adaptor
    hexi::binary_stream stream(adaptor);

    // Use buffer_adaptor's pointer / size interface
    // (exact names may vary; the intent is shown here)
    auto read_ptr      = adaptor.read_data();   // pointer to current read position
    auto readable_size = adaptor.read_size();   // number of readable bytes left

    // Ensure we have enough data for the header
    constexpr std::size_t header_size =
        sizeof(PacketHeader::magic) +
        sizeof(PacketHeader::version) +
        sizeof(PacketHeader::flags);

    if (readable_size < header_size) {
        // In a real application you might throw, set an error, or return a sentinel
        return PacketHeader{0, 0, 0};
    }

    // Use binary_stream's zero-copy operation to obtain a view of the header bytes
    auto header_bytes = stream.read_span<std::byte>(header_size);

    // Interpret the span as a PacketHeader without copying
    const auto* header_ptr =
        reinterpret_cast<const PacketHeader*>(header_bytes.data());

    return *header_ptr;
}
