```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Wrap the incoming span with a Hexi buffer adaptor (read-only).
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream over that adaptor.
    hexi::binary_stream stream(adaptor);

    // 1. Read the 32-bit header.
    uint32_t header{};
    stream.read(header); // equivalent to: stream >> header;

    // 2. Get a "view" of the remaining bytes in the stream without copying.
    auto remaining = stream.view<std::span<const uint8_t>>();

    // 3. Find the null terminator in the remaining buffer.
    std::size_t len = 0;
    while (len < remaining.size() && remaining[len] != 0) {
        ++len;
    }

    // Construct a string_view over the characters up to (but not including) the
