std::vector<uint8_t> peek_data_from_buffer(const hexi::pmc::buffer_read& buffer, size_t bytes_to_peek) {
    std::vector<uint8_t> result(bytes_to_peek);
    buffer.copy(result.data(), bytes_to_peek);
    return result;
}

