TEST(DynamicBuffer, PeekData) {
    hexi::dynamic_buffer<1024> buffer;
    std::vector<uint8_t> data = {1, 2, 3, 4, 5, 6, 7, 8};
    buffer.write(data.data(), data.size());

    auto peeked = peek_data_from_buffer(buffer, 3);

