output.text:
```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek) {
    // Clamp to the number of readable bytes currently in the buffer
    const auto available = buffer.readable_bytes();
    const auto to_copy   = std::min(available, bytes_to_peek);

    std::vector<uint8_t> out(to_copy);

    // dynamic_buffer exposes indexed access from the current read position
    // without modifying it, so we can safely copy out the bytes.
    for (size_t i = 0; i < to_copy; ++i) {
        out[i] = static_cast<uint8_t>(buffer[i]);
    }

    return out;
}
```

