```cpp
#include <hexi/allocators/tls_block_allocator.h>
#include <hexi/detail/intrusive_storage.h>
#include <cstdint>

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
using tls_allocator_type =
    hexi::tls_block_allocator<hexi::detail::intrusive_storage<block_size>, allocator_count>;

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
void enter_thread_with_allocator(tls_allocator_type<block_size, allocator_count>& allocator) {
    // Initialize per‑thread allocator state. The Hexi tls_block_allocator
    // exposes this via an explicit thread_enter() (or similarly named) API.
    //
    // We simply delegate to that API here so that any necessary thread-local
    // bookkeeping is set up before the allocator is used on this thread.
    allocator.thread_enter();
}

template<std::size_t block_size = 1024, std::size_t allocator_count = 100>
void exit_thread_with_allocator(tls_allocator_type<block_size, allocator_count>& allocator) {
    // Tear down per‑thread allocator state for the current thread.
    // This should be called before the thread exits and after the last
    // allocation has been deallocated on this thread.
    allocator.thread_exit();
}
