```cpp
#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    // Use Hexi's conditional_reverse to perform the endian conversion.
    // This will only byteswap when `from` and `to` differ.
    return hexi::conditional_reverse<from, to>(value);
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    // Dispatch to the compile-time version when the endianness values
    // are known, otherwise use a generic byteswap-based implementation.
    if (from == to) {
        return value;
    }

    // Handle the common cases where one of the endianness values is native.
    if (from == std::endian::native && to == std::endian::little) {
        return hexi::conditional_reverse<std::endian::native, std::endian::little>(value);
    }
    if (from == std::endian::native && to == std::endian::big) {
        return hexi::conditional_reverse<std::endian::native, std::endian::big>(value);
    }
    if (from == std::endian::little && to == std::endian::native) {
        return hexi::conditional_reverse<std::endian::little, std::endian::native>(value);
    }
    if (from == std::endian::big && to == std::endian::native) {
        return hexi::conditional_reverse<std::endian::big, std::endian::native>(value);
    }

    // For little <-> big, or any other differing pair, just byteswap.
    if constexpr (std::is_same_v<T, float>) {
        auto u = std::bit_cast<std::uint32_t>(value);
        u = std::byteswap(u);
        return std::bit_cast<float>(u);
    } else if constexpr (std::is_same_v<T, double>) {
        auto u = std::bit_cast<std::uint64_t>(value);
        u = std::byteswap(u);
        return std::bit_cast<double>(u);
    } else {
        return std::byteswap(value);
    }
}
