template<typename T>
void convert_from_big_endian_inplace(T& value) {
    // Big-endian stored value -> native endian value
    hexi::endian::big_to_native_inplace(value);
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    // Little-endian stored value -> native endian value
    hexi::endian::little_to_native_inplace(value);
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    if constexpr (from == to) {
        // No conversion needed
        return;
    } else if constexpr (from == std::endian::native && to == std::endian::big) {
        hexi::endian::native_to_big_inplace(value);
    } else if constexpr (from == std::endian::native && to == std::endian::little) {
        hexi::endian::native_to_little_inplace(value);
    } else if constexpr (from == std::endian::big && to == std::endian::native) {
        hexi::endian::big_to_native_inplace(value);
    } else if constexpr (from == std::endian::little && to == std::endian::native) {
        hexi::endian::little_to_native_inplace(value);
    } else {
        // The only remaining meaningful case is big <-> little,
        // which is equivalent to a byte swap in all supported types.
        hexi::endian::conditional_reverse_inplace<from, to>(value);
    }
}
