```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min
#include <cstddef>   // for std::byte

// 1. Preview data in intrusive_storage without advancing the read pointer.
template<std::size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    std::size_t bytes_to_preview
) {
    using storage_type = typename hexi::detail::intrusive_storage<block_size>::value_type;

    std::size_t readable =
        (storage.write_offset >= storage.read_offset)
            ? static_cast<std::size_t>(storage.write_offset - storage.read_offset)
            : 0; // should not happen for this simple storage, but guard anyway

    std::size_t to_copy = std::min(bytes_to_preview, readable);

    std::vector<uint8_t> result;
    result.reserve(to_copy);

    for(std::size_t i = 0; i < to_copy; ++i) {
        const storage_type& v = storage.storage[storage.read_offset + i];

        if constexpr (std::is_same_v<storage_type, std::byte>) {
            result.push_back(static_cast<uint8_t>(v));
        } else if constexpr (std::is_same_v<storage_type, uint8_t>) {
            result.push_back(v);
        } else if constexpr (std::is_same_v<storage_type, char>) {
            result.push_back(static_cast<uint8_t>(static_cast<unsigned char>(v)));
        } else if constexpr (std::is_same_v<storage_type, unsigned char>) {
            result.push_back(static_cast<uint8_t>(v));
        } else {
            // Fallback: reinterpret the stored value byte-wise.
            const uint8_t* p = reinterpret_cast<const uint8_t*>(&v);
            for(std::size_t b = 0; b < sizeof(storage_type) && result.size() < to_copy; ++b) {
                result.push_back(p[b]);
            }
        }
    }

    return result;
}

// 2. Buffer status structure.
template<std::size_t block_size = 1024>
struct BufferStatus {
    std::size_t readable_size;
    std::size_t free_space;
};

// 2. Check the status of an intrusive_storage buffer.
BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status{};

    // readable bytes = data between read_offset and write_offset
    if (storage.write_offset >= storage.read_offset) {
        status.readable_size =
            static_cast<std::size_t>(storage.write_offset - storage.read_offset);
    } else {
        status.readable_size = 0; // non-wrapping simple storage, guard
    }

    // free space = remaining capacity after write_offset
    constexpr std::size_t capacity = 1024;
    if (storage.write_offset <= capacity) {
        status.free_space =
            static_cast<std::size_t>(capacity - storage.write_offset);
    } else {
        status.free_space = 0;
    }

    return status;
}

// 3. Reset both read and write offsets.
template<std::size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    storage.clear();
}
