```cpp
#include <hexi/file_buffer.h>
#include <hexi/pmc/binary_stream.h>
#include <filesystem>

size_t get_file_readable_size(const std::filesystem::path& file_path) {
    // Open the file buffer in read-only mode (default behavior)
    hexi::file_buffer fb(file_path.string().c_str());

    // Create a non-throwing binary_stream on top of the file_buffer
    hexi::pmc::binary_stream stream(fb, hexi::no_throw);

    // If the stream is already in an error state, size is 0
    if (!stream) {
        return 0;
    }

    // Read until we hit EOF or an error, counting bytes
    std::size_t readable_size = 0;
    char ch;

    while (true) {
        auto bytes_read = fb.read(&ch, 1);
        if (bytes_read == 0) {
            // Either EOF or error; stop
            break;
        }
        ++readable_size;
    }

    return readable_size;
}

bool is_file_buffer_valid(const std::filesystem::path& file_path) {
    // Open the file buffer; constructor may fail internally
    hexi::file_buffer fb(file_path.string().c_str());

    // Use a non-throwing binary_stream to check error state
    hexi::pmc::binary_stream stream(fb, hexi::no_throw);

    // The stream converts to bool: true if state() == stream_state::ok
    return static_cast<bool>(stream);
}
```

