```cpp
#include <hexi/file_buffer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open the file using Hexi's file_buffer (read-only by default)
    hexi::file_buffer fbuf(file_path.string().c_str());

    // Wrap it in a binary_stream_reader with no-throw so we can safely probe
    hexi::pmc::binary_stream_reader stream(fbuf, hexi::no_throw);

    // Remember the current logical read position in the Hexi buffer
    const auto original_pos = fbuf.read_position(); // assumes file_buffer exposes this

    // Allocate the destination buffer
    std::vector<uint8_t> header;
    header.resize(header_size);

    // Try to read up to header_size bytes
    std::size_t bytes_read = stream.read(reinterpret_cast<char*>(header.data()), header_size);

    // Restore the original read position so downstream code sees an unchanged stream
    fbuf.set_read_position(original_pos); // assumes setter for the read pointer

    // If fewer bytes were available, shrink the vector accordingly
    if (bytes_read < header_size) {
        header.resize(bytes_read);
    }

    return header;
}
```

