template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                          const std::vector<uint8_t>& data) {
    // Write as many bytes as fit into the remaining buffer space.
    const auto* src = reinterpret_cast<const std::byte*>(data.data());
    const std::size_t to_write = data.size();

    // static_buffer::write(void*, std::size_t) is the standard interface
    // used elsewhere in the repo (e.g. dynamic_buffer in tests).
    buffer.write(src, to_write);
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                                           size_t bytes_to_read) {
    std::vector<uint8_t> result(bytes_to_read);
    if (bytes_to_read == 0) {
        return result;
    }

    // Read from the buffer into our result vector.
    // static_buffer::read(void*, std::size_t) advances the internal read pointer.
    buffer.read(reinterpret_cast<std::byte*>(result.data()), bytes_to_read);

    return result;
}

