output.text:
```cpp
#include <hexi/static_buffer.h>
#include <cstddef>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;      // total capacity of the buffer
    size_t current_size;  // amount of readable data currently stored
    size_t free_space;    // remaining writable space
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    BufferInfo<> info{};

    // Total capacity is the compile-time buffer size
    info.capacity = 1024;

    // static_buffer exposes readable and writable offsets via read_offset/write_offset
    // in its full definition (not shown in the snippet).
    //
    // Current readable size = amount of data between read and write positions.
    auto read_pos  = buffer.read_offset();
    auto write_pos = buffer.write_offset();

    info.current_size = (write_pos >= read_pos)
                        ? (write_pos - read_pos)
                        : 0; // defensive, should not normally happen

    // Free space is total capacity minus the readable data
    info.free_space = info.capacity - info.current_size;

    return info;
}
```

