```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>
#include <cstddef>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(
    const hexi::static_buffer<std::byte, buffer_size>& buffer,
    size_t bytes_to_preview
) {
    // Determine how many bytes are currently available to read.
    // static_buffer in Hexi exposes a size() member that returns the number
    // of readable bytes between the internal read_ and write_ pointers.
    const std::size_t available = buffer.size();

    // Clamp bytes_to_preview to the available data.
    const std::size_t to_copy = std::min<std::size_t>(bytes_to_preview, available);

    std::vector<uint8_t> result;
    result.reserve(to_copy);

    // static_buffer provides read_iterator() / read_end() iterators
    // (random-access / contiguous) over the readable region without
    // advancing the read pointer. We can safely copy from them.
    auto it  = buffer.read_iterator();
    auto end = buffer.read_end();

    // Copy at most `to_copy` bytes from the readable range.
    for (std::size_t i = 0; i < to_copy && it != end; ++i, ++it) {
        result.push_back(static_cast<uint8_t>(*it));
    }

    return result;
}
```

