#include <hexi/pmc/stream_base.h>
#include <hexi/shared.h>

size_t get_stream_size(const hexi::pmc::stream_base& stream) {
    // stream_base holds a reference to a buffer_base (buffer_),
    // which provides a size() member returning the buffer size.
    // buffer_ is accessible here via the public buffer() accessor.
    return stream.buffer().size();
}

bool is_stream_empty(const hexi::pmc::stream_base& stream) {
    // A stream is considered empty if its underlying buffer size is zero.
    return get_stream_size(stream) == 0;
}

struct StreamInfo {
    hexi::stream_state state;
    size_t buffer_size;
    bool is_empty;
};

StreamInfo get_stream_state_info(const hexi::pmc::stream_base& stream) {
    StreamInfo info{};
    // stream_base exposes its current state via a state() accessor.
    info.state = stream.state();
    info.buffer_size = get_stream_size(stream);
    info.is_empty = (info.buffer_size == 0);
    return info;
}
