void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
	// Write length as a 32-bit unsigned integer (prefixed format),
	// then write the raw character data.
	std::uint32_t len = static_cast<std::uint32_t>(str.size());
	writer.write(len);
	if (len != 0) {
		writer.write_bytes(str.data(), len);
	}
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
	// Read the length prefix, then read that many bytes into a string.
	std::uint32_t len = 0;
	reader.read(len);

	std::string result;
	if (len == 0) {
		return result;
	}

	result.resize(len);
	reader.read_bytes(result.data(), len);
	return result;
}
