```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcpy

void write_data_to_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          std::uint32_t value,
                          const void* data,
                          std::size_t length) {
    // Write the integer value in its raw binary form
    buffer.write(&value, sizeof(value));

    // Write the byte array
    if (length > 0 && data != nullptr) {
        buffer.write(data, length);
    }
}

void read_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           std::uint32_t& value,
                           void* data,
                           std::size_t length) {
    // Read the integer value
    buffer.read(&value, sizeof(value));

    // Read the byte array
    if (length > 0 && data != nullptr) {
        buffer.read(data, length);
    }
}

struct BufferInfo {
    std::size_t size;
    std::size_t free_space;
};

BufferInfo get_buffer_info(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferInfo info{};
    info.size = buffer.size();

    // For a std::vector-based adaptor, capacity() is the total allocated space.
    // The free space for writing is the remaining capacity beyond current size.
    const auto& underlying = buffer.get_buffer(); // assumes buffer_adaptor provides access
    if (underlying.capacity() >= info.size) {
        info.free_space = underlying.capacity() - info.size;
    } else {
        info.free_space = 0;
    }

    return info;
}
