```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* data, std::size_t length) {
    // Use the non-template copy() overload to copy raw bytes without
    // advancing the read pointer.
    buffer.copy(data, length);
}

template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, T& value) {
    // Use the template copy() overload to copy a single value of type T
    // without advancing the read pointer.
    buffer.copy(value);
}

bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, const void* expected, std::size_t length) {
    // Peek into the buffer without consuming bytes, then compare
    // with the expected data.
    std::vector<std::byte> tmp(length);
    if (length != 0) {
        buffer.copy(tmp.data(), length);
        return std::memcmp(tmp.data(), expected, length) == 0;
    }
    // For zero length, treat as equal by definition.
    return true;
}
