#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/buffer_read.h>
#include <vector>
#include <cstdint>
#include <cstddef>

std::size_t find_byte_in_buffer(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte value
) {
    // Use the buffer_read interface provided by Hexi. We iterate from 0 to
    // buffer.size() and compare each byte using operator[].
    const std::size_t sz = buffer.size();

    for (std::size_t i = 0; i < sz; ++i) {
        if (buffer[i] == value) {
            return i;
        }
    }

    return hexi::pmc::buffer_read::npos;
}

std::size_t find_delimiter_position(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte delimiter
) {
    // Reuse the same scanning logic as in find_byte_in_buffer.
    const std::size_t sz = buffer.size();

    for (std::size_t i = 0; i < sz; ++i) {
        if (buffer[i] == delimiter) {
            return i;
        }
    }

    return hexi::pmc::buffer_read::npos;
}

bool check_buffer_contains(
    hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
    std::byte value
) {
    // Simply check if find_byte_in_buffer returns a valid position.
    return find_byte_in_buffer(buffer, value) != hexi::pmc::buffer_read::npos;
}
