```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcpy
#include <limits>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          std::size_t bytes) {
	// buffer_adaptor ultimately derives from pmc::buffer_read / buffer,
	// which provide advancing of the read pointer.
	//
	// We only need to advance the read position by `bytes`, effectively
	// skipping that many bytes from the current read offset.
	buffer.advance_read(bytes);
}

struct MessageHeader {
	uint16_t message_type;
	uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
	MessageHeader header{};

	// We assume the data in the buffer is stored in native endianness and
	// is tightly packed as:
	//   uint16_t message_type;
	//   uint32_t body_length;
	//
	// Read the 2-byte message_type.
	{
		std::byte tmp[sizeof(header.message_type)];
		buffer.read(tmp, sizeof(tmp));
		std::memcpy(&header.message_type, tmp, sizeof(header.message_type));
	}

	// Read the 4-byte body_length.
	{
		std::byte tmp[sizeof(header.body_length)];
		buffer.read(tmp, sizeof(tmp));
		std::memcpy(&header.body_length, tmp, sizeof(header.body_length));
	}

	// Now skip the body based on the body_length field.
	// Rely on the adaptor's bounds/error handling.
	if (header.body_length > std::numeric_limits<std::size_t>::max()) {
		// In unrealistic case of overflow; in practice uint32_t always fits in size_t
		// on platforms Hexi typically targets, but guard anyway.
		buffer.advance_read(buffer.size()); // attempt to move to end
	} else {
		skip_bytes_in_buffer(buffer, static_cast<std::size_t>(header.body_length));
	}

	return header;
}
