```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcpy

// 1. Check if the buffer supports write seeking.
bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    return buffer.can_write_seek();
}

// 2. Seek the write position using write_seek() with different directions.
void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                         hexi::buffer_seek direction,
                         std::size_t offset) {
    // Delegate directly to the underlying write_seek
    buffer.write_seek(direction, offset);
}

// 3. Write a header at the beginning, write body, then seek back to update header.
void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                               uint32_t header_value) {
    // Ensure the buffer supports write seeking
    if (!buffer.can_write_seek()) {
        return; // or throw, depending on the surrounding project's error policy
    }

    // Save current write position (relative to the beginning).
    // We do this by first seeking to the current position with offset 0 from current
    // and then assuming that subsequent absolute seeks are supported.
    //
    // In the Hexi buffer_write interface, write_seek operates on a logical write pointer.
    // For buffer_adaptor, the initial write position is usually buffer.size(),
    // so we can get the current write index by seeking from current with offset 0,
    // but the interface doesn't return it directly. Instead, we follow a simple protocol:
    //
    // 1. Seek to the beginning, remember that index.
    // 2. Seek back to the end again by using buffer.size() as an absolute offset.
    //
    // However, buffer_adaptor internally tracks the write pointer and write_seek
