```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

// Encode an unsigned integer using standard LEB128-style varint.
// Works for any unsigned integer type T.
template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    static_assert(std::is_unsigned_v<T>, "encode_varint requires an unsigned integer type");

    std::size_t bytes_written = 0;
    std::uint8_t byte;

    do {
        byte = static_cast<std::uint8_t>(value & 0x7F);
        value >>= 7;
        if (value != 0) {
            byte |= 0x80; // set continuation bit
        }
        writer.write(byte);
        ++bytes_written;
    } while (value != 0);

    return bytes_written;
}

// Decode an unsigned integer that was encoded with encode_varint.
// Works for any unsigned integer type T.
template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    static_assert(std::is_unsigned_v<T>, "decode_varint requires an unsigned integer type");

    T result = 0;
    std::size_t shift = 0;
    std::uint8_t byte = 0;

    while (true) {
        reader.read(byte);

        T chunk = static_cast<T>(byte & 0x7F);
        result |= (chunk << shift);

        if ((byte & 0x80) == 0) {
            break; // last byte
        }

        shift += 7;

        // Prevent undefined behaviour if the encoded value exceeds the
        // capacity of T. We stop accumulating further bits.
        if (shift >= sizeof(T) * 8) {
            break;
        }
    }

    return result;
}

// Helper to test roundtrip correctness: encode then decode and compare.
template<typename T>
bool encode_decode_roundtrip(T original_value) {
    static_assert(std::is_unsigned_v<T>, "encode_decode_roundtrip requires an unsigned integer type");

    std::vector<std::uint8_t> storage;
    hexi::pmc::buffer_adaptor<std::vector<std::uint8_t>> adaptor(storage);

    // Writer and reader share the same underlying buffer.
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint<T>(writer, original_value);

    hexi::pmc::binary_stream_reader reader(adaptor);
    T decoded = decode_varint<T>(reader);

    return decoded == original_value;
}
```

