#include <hexi/exception.h>
#include <hexi/pmc/binary_stream.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct ReadLimitInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info{0, 0, 0, false};

    try {
        // Create a small buffer and a stream with a strict read limit, then
        // attempt to read past that limit to deliberately trigger the exception.
        std::array<std::uint8_t, 4> buffer{0, 1, 2, 3};
        hexi::pmc::buffer_adaptor adaptor(buffer);
        // Set a read limit smaller than the amount we'll attempt to read
        hexi::pmc::binary_stream stream(adaptor, 2);

        std::uint8_t dest[4];
        // This read should exceed the read limit and throw hexi::stream_read_limit
        stream.read(dest, sizeof(dest));
    } catch (const hexi::stream_read_limit& ex) {
        info.read_size  = ex.read_size();
        info.total_read = ex.total_read();
        info.read_limit = ex.read_limit();
        info.occurred   = true;
    }

    return info;
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream,
                                         void* destination,
                                         std::size_t length) {
    ReadLimitInfo info{0, 0, 0, false};

    try {
        stream.read(destination, length);
    } catch (const hexi::stream_read_limit& ex) {
        info.read_size  = ex.read_size();
        info.total_read = ex.total_read();
        info.read_limit = ex.read_limit();
        info.occurred   = true;
    }

    return info;
}
