    // 2. data with length prefix (Hexi's std::string support does this)
    // 3. 16 bytes of 0x00 padding using fill<16>(0x00)
    // 4. footer (uint32_t)
    stream << packet.header
           << packet.data;

    // Insert exactly 16 bytes of zero padding
    stream.fill<16>(0x00);

    // Finally write the footer
    stream << packet.footer;

    return buffer;
}
