```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // backing buffer that the write adaptor will append to
    std::vector<std::uint8_t> buffer;

    // create a write adaptor on top of the backing buffer
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // ensure there is enough free space before writing
    if (write_adaptor.free() < input_data.size()) {
        // grow the backing buffer to accommodate the input
        buffer.resize(buffer.size() + (input_data.size() - write_adaptor.free()));
        // tell the adaptor that its write-space has increased
        write_adaptor.advance_write(input_data.size() - write_adaptor.free());
    }

    // write the input data into the adaptor/buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // now create a read adaptor to read the data back
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // size() tells us how many bytes are readable
    const std::size_t readable = read_adaptor.size();

    std::vector<std::uint8_t> output(readable);
    if (readable != 0) {
        // read() consumes from the adaptor into our output vector
        read_adaptor.read(output.data(), readable);
    }

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // create a read adaptor over the provided data
    hexi::pmc::buffer_read_adaptor read_adaptor(const_cast<std::vector<std::uint8_t>&>(buffer_data));

    // cannot peek more than is currently readable
    const std::size_t available = read_adaptor.size();
    const std::size_t to_peek = std::min(peek_size, available);

    std::vector<std::uint8_t> peeked(to_peek);

    if (to_peek == 0) {
        return peeked;
    }

    // read_ptr() gives us a pointer to the current read position
    const std::uint8_t* current_read_ptr =
        static_cast<const std::uint8_t*>(read_adaptor.read_ptr());

    // copy() allows us to inspect/peek without advancing the read cursor
    read_adaptor.copy(peeked.data(), to_peek);

    // After peeking, actually consume the same amount of data using read()
    std::vector<std::uint8_t> consumed(to_peek);
    read_adaptor.read(consumed.data(), to_peek);

    // Return the data we peeked (which should match what we consumed)
    return peeked;
}
