```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

// Writes the provided chunks into a Hexi PMC buffer in multiple calls,
// checking available space with free() before each write.
// Returns the final size() of the buffer (total bytes written).
std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Choose a capacity large enough for typical examples; Hexi's PMC
    // buffers are usually fixed-capacity.
    // Adjust as needed for the actual environment.
    constexpr std::size_t kCapacity = 4096;

    hexi::pmc::buffer_write_adaptor adaptor(kCapacity);

    for (const auto& chunk : chunks) {
        const std::uint8_t* data = chunk.data();
        std::size_t remaining = chunk.size();

        // Write this chunk possibly in several sub-writes if it doesn't fit
        while (remaining > 0 && adaptor.free() > 0) {
            std::size_t to_write = std::min<std::size_t>(remaining, adaptor.free());
            adaptor.write(data, to_write);

            data      += to_write;
            remaining -= to_write;

            // If adaptor.free() is 0, the buffer is full; we stop writing.
        }

        // If buffer is full, no further chunks can be written
        if (adaptor.free() == 0) {
            break;
        }
    }

    // Return how many bytes ended up in the buffer
    return adaptor.size();
}

// Reads from a Hexi PMC buffer in partial chunks until it is empty.
// - buffer: source data to preload into the PMC buffer
// - chunk_size: how many bytes to try to read per step
// Returns all data read out (should match the buffer content up to capacity).
std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    if (chunk_size == 0) {
        return {};
    }

    // Initialize a read adaptor over the given buffer contents.
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    std::vector<uint8_t> result;
    result.reserve(buffer.size());

    while (adaptor.size() > 0) {
        std::size_t to_read = std::min<std::size_t>(chunk_size, adaptor.size());
        std::vector<std::uint8_t> tmp(to_read);

        adaptor.read(tmp.data(), to_read);
        result.insert(result.end(), tmp.begin(), tmp.end());

        // adaptor.size() will have decreased; loop continues until zero
    }

    return result;
}
