```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a read adaptor over the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header header{};

    // Use copy() to peek into the buffer without advancing the read cursor.
    // copy() copies from the current read position into our local struct.
    adaptor.copy(&header, sizeof(Header));

    // Use read_ptr() to verify that the read cursor has not moved.
    // Because we only used copy(), the pointer should still point to the
    // first byte of the underlying buffer as long as the buffer is non‑empty.
    const std::byte* ptr = adaptor.read_ptr();
    if (!buffer.empty()) {
        // Simple sanity check that the adaptor still points to the start
        // of the buffer and thus no data was consumed.
        const std::byte* expected =
            reinterpret_cast<const std::byte*>(buffer.data());
        (void)expected; // Avoid unused-variable warnings in release builds
        (void)ptr;      // We don't assert here; this is just demonstration.
    }

    // Return the peeked header. The adaptor's read position is unchanged.
    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    std::vector<uint8_t> result;

    if (buffer.empty()) {
        return result;
    }

    // Peek at the first byte without consuming it
    std::uint8_t first = 0;
    adaptor.copy(&first, sizeof(first));

    // Example condition: only read and return the rest of the buffer
    // if the first byte is 0x42.
    if (first == 0x42) {
        // Now actually consume the data from the stream.
        // First read the first byte we already peeked.
        std::uint8_t consumed_first = 0;
        adaptor.read(&consumed_first, sizeof(consumed_first));

        // Then read the remaining bytes.
        std::size_t remaining = buffer.size() - sizeof(consumed_first);
        result.resize(1 + remaining);
        result[0] = consumed_first;

        if (remaining > 0) {
            adaptor.read(result.data() + 1, remaining);
        }
    } else {
        // Condition not met: do not consume anything, return empty vector.
        // (The adaptor goes out of scope here; buffer is untouched.)
    }

    return result;
}
