#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <span>

struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Backing buffer for the adaptor / stream
    std::vector<uint8_t> buffer;

    // Wrap the buffer in a Hexi adaptor and stream (native endian, manual conversion)
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::endian::native);

    using hexi::endian::native_to_big;

    // Serialize message_id as big-endian
    {
        uint32_t be_message_id = native_to_big(packet.message_id);
        stream.write(be_message_id);
    }

    // Serialize count of data_values as big-endian uint32_t
    {
        uint32_t count = static_cast<uint32_t>(packet.data_values.size());
        uint32_t be_count = native_to_big(count);
        stream.write(be_count);
    }

    // Serialize data_values as big-endian uint16_t elements
    {
        std::vector<uint16_t> tmp;
        tmp.reserve(packet.data_values.size());
        for (uint16_t v : packet.data_values) {
            tmp.push_back(native_to_big(v));
        }
        stream.write_container(tmp);
    }

    // Serialize checksum as big-endian
    {
        uint32_t be_checksum = native_to_big(packet.checksum);
        stream.write(be_checksum);
    }

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet{};

    // Read-only span adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::endian::native);

    using hexi::endian::big_to_native;

    // Read and convert message_id
    {
        uint32_t be_message_id = 0;
        stream.read(be_message_id);
        packet.message_id = big_to_native(be_message_id);
    }

    // Read and convert count of data_values
    uint32_t count = 0;
    {
        uint32_t be_count = 0;
        stream.read(be_count);
        count = big_to_native(be_count);
    }

    // Read data_values as big-endian uint16_t, then convert each element
    {
        std::vector<uint16_t> tmp;
        tmp.resize(count);
        stream.read_container(tmp);

        packet.data_values.resize(count);
        for (std::size_t i = 0; i < count; ++i) {
            packet.data_values[i] = big_to_native(tmp[i]);
        }
    }

    // Read and convert checksum
    {
        uint32_t be_checksum = 0;
        stream.read(be_checksum);
        packet.checksum = big_to_native(be_checksum);
    }

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header{};

    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::endian::native);

    using hexi::endian::big_to_native;

    // Get a zero-copy view of the first 4 bytes (message_id)
    auto id_span = stream.span<std::byte>(sizeof(uint32_t));

    uint32_t be_message_id = 0;
    std::memcpy(&be_message_id, id_span.data(), sizeof(uint32_t));
    header.message_id = big_to_native(be_message_id);

    // Advance past the header
    stream.skip(sizeof(uint32_t));

    return header;
}
