#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Serialization (writing)
    void serialise(auto& adaptor) const {
        using namespace hexi;

        // Wrap adaptor in a binary_stream if needed
        binary_stream stream(adaptor);

        // 1. Write sensor_id directly (no endian conversion requested here)
        stream.write(sensor_id);

        // 2. Write number of temperatures so we can read them back
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        stream.write(count);

        // 3. Convert each temperature from native to little-endian at runtime
        for (float t : temperatures) {
            float tmp = t;
            endian::conditional_reverse(tmp, std::endian::native, std::endian::little);
            stream.write(tmp);
        }

        // 4. Convert pressure from native to little-endian at runtime
        double p = pressure;
        endian::conditional_reverse(p, std::endian::native, std::endian::little);
        stream.write(p);
    }

    // Deserialization (reading)
    void serialise(auto& adaptor) {
        using namespace hexi;

        binary_stream stream(adaptor);

        // 1. Read sensor_id directly
        stream.read(sensor_id);

        // 2. Read number of temperatures and resize vector
        uint32_t count = 0;
        stream.read(count);
        temperatures.resize(count);

        // 3. Read each temperature and convert from little-endian to native in-place
        for (uint32_t i = 0; i < count; ++i) {
            float tmp{};
            stream.read(tmp);
            endian::little_to_native_inplace(tmp);
            temperatures[i] = tmp;
        }

        // 4. Read pressure and convert from little-endian to native in-place
        double p{};
        stream.read(p);
        endian::little_to_native_inplace(p);
        pressure = p;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    using namespace hexi;

    std::vector<uint8_t> buffer;
    buffer_adaptor adaptor(buffer);
    binary_stream stream(adaptor);

    // Use the stream's serialise method for the entire structure
    stream.serialise(data);

    // buffer_adaptor writes directly into buffer
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    using namespace hexi;

    buffer_adaptor adaptor(buffer);
    binary_stream stream(adaptor);

    MeasurementData data;
    // Use the stream's deserialise method for the entire structure
    stream.deserialise(data);

    return data;
}

